import os
import sys
import base64

def write_file(path, content_b64):
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, "wb") as f:
        f.write(base64.b64decode(content_b64))

base_dir = "/app"


try:
    write_file(os.path.join(base_dir, 'app/agents/orchestrator.py'), "")
    print("Sucesso: app/agents/orchestrator.py")
except Exception as e:
    print(f"Erro em app/agents/orchestrator.py: {e}")

